PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "role" varchar check ("role" in ('super_admin', 'admin', 'reviewer', 'author')) not null default 'author', "is_active" tinyint(1) not null default '1', "institution" varchar, "phone" varchar, "bio" text, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "avatar_path" varchar);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "paper_authors" ("id" integer primary key autoincrement not null, "paper_id" integer not null, "name" varchar not null, "email" varchar, "institution" varchar, "is_corresponding" tinyint(1) not null default '0', "order" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("paper_id") references "papers"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "papers" ("id" integer primary key autoincrement not null, "title" varchar not null, "abstract" text not null, "keywords" varchar, "file_path" varchar, "file_name" varchar, "author_id" integer not null, "assigned_reviewer_id" integer, "status" varchar check ("status" in ('pending', 'under_review', 'accepted', 'revision', 'rejected', 'published')) not null default 'pending', "version" integer not null default '1', "admin_notes" text, "created_at" datetime, "updated_at" datetime, "word_file_path" varchar, "word_file_name" varchar, "category" varchar, "budget" varchar, foreign key("author_id") references "users"("id") on delete cascade, foreign key("assigned_reviewer_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "activity_logs" ("id" integer primary key autoincrement not null, "user_id" integer, "action" varchar not null, "description" text, "subject_type" varchar, "subject_id" integer, "properties" text, "ip_address" varchar, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "personal_access_tokens" ("id" integer primary key autoincrement not null, "tokenable_type" varchar not null, "tokenable_id" integer not null, "name" text not null, "token" varchar not null, "abilities" text, "last_used_at" datetime, "expires_at" datetime, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "reviews" ("id" integer primary key autoincrement not null, "paper_id" integer not null, "reviewer_id" integer not null, "comment" text not null, "private_comment" text, "decision" varchar check ("decision" in ('accept', 'minor_revision', 'major_revision', 'reject')) not null, "status" varchar check ("status" in ('pending', 'completed')) not null default 'completed', "created_at" datetime, "updated_at" datetime, "file_path" varchar, "file_name" varchar, "word_file_path" varchar, "word_file_name" varchar, foreign key("paper_id") references "papers"("id") on delete cascade, foreign key("reviewer_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "notifications" ("id" integer primary key autoincrement not null, "user_id" integer not null, "type" varchar not null, "title" varchar not null, "message" text not null, "link" varchar, "read_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "discussions" ("id" integer primary key autoincrement not null, "paper_id" integer not null, "user_id" integer not null, "message" text not null, "created_at" datetime, "updated_at" datetime, foreign key("paper_id") references "papers"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE INDEX "personal_access_tokens_tokenable_type_tokenable_id_index" on "personal_access_tokens" ("tokenable_type", "tokenable_id");
CREATE UNIQUE INDEX "personal_access_tokens_token_unique" on "personal_access_tokens" ("token");
CREATE INDEX "personal_access_tokens_expires_at_index" on "personal_access_tokens" ("expires_at");
COMMIT;
