INSERT INTO papers VALUES(1,'Implementasi Deep Learning untuk Klasifikasi Penyakit Tanaman','Penelitian ini mengusulkan metode berbasis deep learning menggunakan Convolutional Neural Network (CNN) untuk mengklasifikasikan penyakit tanaman padi secara otomatis. Dataset yang digunakan terdiri dari 10.000 gambar daun padi yang dikumpulkan dari berbagai daerah di Indonesia.','deep learning, CNN, klasifikasi, penyakit tanaman, padi',NULL,NULL,5,3,'published',2,NULL,'2026-05-08 17:11:30','2026-05-08 17:11:30',NULL,NULL,NULL,NULL);
INSERT INTO papers VALUES(2,'Analisis Keamanan Sistem Informasi Berbasis Cloud menggunakan Zero-Trust Architecture','Paper ini membahas implementasi Zero-Trust Architecture pada sistem informasi berbasis cloud. Penelitian dilakukan dengan menganalisis kerentanan pada model keamanan tradisional dan membandingkannya dengan pendekatan Zero-Trust.','keamanan, cloud, zero-trust, sistem informasi',NULL,NULL,6,4,'under_review',1,NULL,'2026-05-08 17:11:30','2026-05-08 17:11:30',NULL,NULL,NULL,NULL);
INSERT INTO papers VALUES(3,'Pengembangan Sistem Rekomendasi Produk E-Commerce menggunakan Collaborative Filtering','Penelitian ini mengembangkan sistem rekomendasi produk untuk platform e-commerce menggunakan algoritma Collaborative Filtering berbasis Matrix Factorization.','sistem rekomendasi, collaborative filtering, e-commerce, machine learning',NULL,NULL,5,NULL,'pending',1,NULL,'2026-05-08 17:11:30','2026-05-08 17:11:30',NULL,NULL,NULL,NULL);
INSERT INTO papers VALUES(4,'Optimasi Algoritma Genetika untuk Penjadwalan Mata Kuliah di Universitas','Penelitian ini mengusulkan pendekatan baru menggunakan Algoritma Genetika yang dioptimasi untuk menyelesaikan masalah penjadwalan mata kuliah yang kompleks.','algoritma genetika, penjadwalan, optimasi, universitas',NULL,NULL,6,3,'revision',1,NULL,'2026-05-08 17:11:30','2026-05-08 17:11:30',NULL,NULL,NULL,NULL);
INSERT INTO papers VALUES(5,'Sistem Deteksi Kualitas Air IoT','Ini adalah abstrak penelitian deteksi kualitas air menggunakan Internet of Things dan sensor kekeruhan secara real-time.','IoT, kualitas air',NULL,NULL,5,NULL,'pending',1,NULL,'2026-05-17 23:40:31','2026-05-17 23:40:31',NULL,NULL,'Penelitian','Rp 12.500.000');
